INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (126401, "2023/09/22 14:59:59", "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", "クローチェ", 1, "2023/06/30 12:00:00", 1, 1.47, 1, 10001, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (126401, "2023/09/22 14:59:59", "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", "クローチェ", 1, "2023/06/30 12:00:00", 2, 2.15, 2, 10002, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (126501, "2023/09/22 14:59:59", "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", "ライラエル", 1, "2023/06/30 12:00:00", 1, 0.0, 2, 10003, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (126501, "2023/09/22 14:59:59", "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", "ライラエル", 1, "2023/06/30 12:00:00", 2, 0.0, 1, 10004, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (127702, "2023/12/22 14:59:59", "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", "リンド", 2, "2023/09/15 15:00:00", 1, 0.0, 2, 10005, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (127702, "2023/12/22 14:59:59", "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", "リンド", 2, "2023/09/15 15:00:00", 2, 0.0, 2, 10006, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (127802, "2023/12/22 14:59:59", "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", "ヴルム", 2, "2023/09/15 15:00:00", 1, 0.0, 1, 10007, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (127802, "2023/12/22 14:59:59", "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", "ヴルム", 2, "2023/09/15 15:00:00", 2, 6.5, 2, 10008, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (129602, "2024/03/22 14:59:59", "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", "アネモネ", 3, "2023/12/15 15:00:00", 1, 0.0, 2, 10009, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (129602, "2024/03/22 14:59:59", "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", "アネモネ", 3, "2023/12/15 15:00:00", 2, 0.0, 2, 10010, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (129701, "2024/03/22 14:59:59", "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", "ネフィ=ネラ", 3, "2023/12/15 15:00:00", 1, 0.0, 1, 10011, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (129701, "2024/03/22 14:59:59", "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", "ネフィ=ネラ", 3, "2023/12/15 15:00:00", 2, 6.2, 2, 10012, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130301, "2024/06/22 14:59:59", "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", "カノン", 4, "2024/03/15 15:00:00", 1, 3.1, 3, 10013, 2002, 5, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130301, "2024/06/22 14:59:59", "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", "カノン", 4, "2024/03/15 15:00:00", 2, 6.15, 3, 10014, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130401, "2024/06/22 14:59:59", "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", "ナーナ", 4, "2024/03/15 15:00:00", 1, 0.0, 2, 10015, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130401, "2024/06/22 14:59:59", "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", "ナーナ", 4, "2024/03/15 15:00:00", 2, 3.35, 2, 10016, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130502, "2024/09/22 14:59:59", "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", "ホウオウ", 5, "2024/06/15 15:00:00", 1, 0.0, 1, 10017, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130502, "2024/09/22 14:59:59", "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", "ホウオウ", 5, "2024/06/15 15:00:00", 2, 3.18, 2, 10018, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130503, "2024/09/22 14:59:59", "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", "ホウオウ", 5, "2024/06/15 15:00:00", 3, 0.0, 4, 10019, 2002, 4, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (123301, "2024/09/22 14:59:59", "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", "ネア", 5, "2024/06/15 15:00:00", 1, 4.9, 1, 10020, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (123301, "2024/09/22 14:59:59", "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", "ネア", 5, "2024/06/15 15:00:00", 2, 4.8, 1, 10021, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (133301, "2024/12/22 14:59:59", "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", "カリザ", 6, "2024/09/15 15:00:00", 1, 4.922, 3, 10022, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (133301, "2024/12/22 14:59:59", "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", "カリザ", 6, "2024/09/15 15:00:00", 2, 9.638, 3, 10023, 2002, 5, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (133401, "2024/12/22 14:59:59", "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", "ミーア", 6, "2024/09/15 15:00:00", 1, 2.88, 1, 10024, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (133401, "2024/12/22 14:59:59", "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", "ミーア", 6, "2024/09/15 15:00:00", 2, 4.818, 5, 10025, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (133002, "2025/03/22 14:59:59", "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", "グレイス", 7, "2024/12/15 15:00:00", 1, 1.78, 2, 10026, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (133002, "2025/03/22 14:59:59", "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", "グレイス", 7, "2024/12/15 15:00:00", 2, 6.15, 1, 10027, 2002, 7, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (133102, "2025/03/22 14:59:59", "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", "ヴァイオレット", 7, "2024/12/15 15:00:00", 1, 4.28, 6, 10028, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (133102, "2025/03/22 14:59:59", "じめじめした商品は\nございませんので\n安心してお買い求め下さい", "ヴァイオレット", 7, "2024/12/15 15:00:00", 2, 0.0, 1, 10029, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (136902, "2025/06/23 14:59:59", "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", "ルルィ", 8, "2025/03/15 15:00:00", 1, 5.53, 2, 10030, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (136902, "2025/06/23 14:59:59", "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", "ルルィ", 8, "2025/03/15 15:00:00", 2, 6.05, 9, 10031, 2002, 7, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (137001, "2025/06/23 14:59:59", "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", "デュラン", 8, "2025/03/15 15:00:00", 1, 0.0, 2, 10032, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (137001, "2025/06/23 14:59:59", "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", "デュラン", 8, "2025/03/15 15:00:00", 2, 0.0, 2, 10033, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (135902, "2025/09/23 14:59:59", "おう\n好きなもん持ってきな", "サツキ", 9, "2025/06/16 15:00:00", 1, 0.0, 2, 10034, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (135902, "2025/09/23 14:59:59", "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", "サツキ", 9, "2025/06/16 15:00:00", 2, 4.935, 1, 10035, 2002, 6, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (135802, "2025/09/23 14:59:59", "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", "ユキノ", 9, "2025/06/16 15:00:00", 1, 7.441, 2, 10036, 2002, 5, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (135802, "2025/09/23 14:59:59", "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", "ユキノ", 9, "2025/06/16 15:00:00", 2, 0.0, 7, 10037, 2002, 7, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130901, "2025/12/22 14:59:59", "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", "クルル", 10, "2025/09/16 15:00:00", 1, 2.295, 2, 10038, 2002, 2, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (130901, "2025/12/22 14:59:59", "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", "クルル", 10, "2025/09/16 15:00:00", 2, 6.281, 1, 10039, 2002, 6, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (137701, "2025/12/22 14:59:59", "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", "ヴォルガーノ", 10, "2025/09/16 15:00:00", 1, 5.549, 2, 10040, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (137701, "2025/12/22 14:59:59", "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", "ヴォルガーノ", 10, "2025/09/16 15:00:00", 2, 2.64, 3, 10041, 2002, 6, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (132801, "2026/03/23 11:59:59", "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", "ライラエル", 11, "2025/12/15 15:00:00", 1, 7.642, 7, 10042, 2002, 4, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (132802, "2026/03/23 11:59:59", "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", "ライラエル", 11, "2025/12/15 15:00:00", 2, 0.0, 1, 10043, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (134502, "2026/03/23 11:59:59", "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", "クローチェ", 11, "2025/12/15 15:00:00", 1, 0.0, 1, 10044, 2002, 1, -470.0, 0.0);
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (134501, "2026/03/23 11:59:59", "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", "クローチェ", 11, "2025/12/15 15:00:00", 2, 3.72, 2, 10045, 2002, 1, -470.0, 0.0);
